//line main.kuki:330
func gatherPrompt(args []string) string {
//line main.kuki:331
	prompt := ""
//line main.kuki:334
	if !isTerminal(os.Stdin) && (len(args) == 0) {
//line main.kuki:335
		data, _ := io.ReadAll(os.Stdin)
//line main.kuki:336
		prompt = strpkg.TrimSpace(string(data))
	}
//line main.kuki:338
	if len(args) > 0 {
//line main.kuki:339
		argText := strpkg.Join(args, " ")
//line main.kuki:340
		if prompt != "" {
//line main.kuki:341
			prompt = fmt.Sprintf("%v\n\n%v", argText, prompt)
		} else {
//line main.kuki:343
			prompt = argText
		}
	}
//line main.kuki:345
	return prompt
}

//line main.kuki:347
func isTerminal(f *os.File) bool {
//line main.kuki:348
	info, err := f.Stat()
//line main.kuki:349
	if err != nil {
//line main.kuki:350
		return false
	}
//line main.kuki:351
	return ((info.Mode() & 0x200000) != 0)
}

//line main.kuki:353
func isTTYOut() bool {
//line main.kuki:354
	return isTerminal(os.Stdout)
}

//line main.kuki:356
func isTTYErr() bool {
//line main.kuki:357
	return isTerminal(os.Stderr)
}

//line main.kuki:359
func maskKey(k string) string {
//line main.kuki:360
	if len(k) < 8 {
//line main.kuki:361
		return "--------"
	}
//line main.kuki:362
	return fmt.Sprintf("%v...%v", k[:4], k[(len(k)-4):])
}

//line main.kuki:364
func truncateFmt(s string, n int) string {
//line main.kuki:365
	s = strpkg.ReplaceAll(s, "\n", " ")
//line main.kuki:366
	if len(s) <= n {
//line main.kuki:367
		return s
	}
//line main.kuki:368
	return fmt.Sprintf("%v...", s[:n])
}

